import { useEffect } from 'react'

// Olla Cocina PAE incrustada (base64) - no requiere archivo externo
const OLLA_IMG = "data:image/png;base64,"

function IntroCocinaPAE({ onTerminada }) {
  useEffect(() => {
    const timer = setTimeout(() => {
      onTerminada()
    }, 3200)
    return () => clearTimeout(timer)
  }, [onTerminada])

  return (
    <div style={estilos.contenedor}>
      <div style={estilos.glow}></div>

      <div style={estilos.ollaWrap}>
        <img src={OLLA_IMG} alt="Cocina PAE" style={estilos.olla} />
        <div style={estilos.shimmer}></div>
      </div>

      <h1 style={estilos.wordmark}>
        <span style={estilos.cocina}>Cocina</span>{' '}
        <span style={estilos.pae}>PAE</span>
      </h1>
      <p style={estilos.tagline}>Software de gestion escolar y rentabilidad</p>

      <style>{`
        @keyframes cpGlowIn {
          0% { opacity: 0; transform: translate(-50%, -50%) scale(0.6); }
          30% { opacity: 1; transform: translate(-50%, -50%) scale(1); }
          100% { opacity: 0.85; transform: translate(-50%, -50%) scale(1.03); }
        }
        @keyframes cpOllaPop {
          0% { opacity: 0; transform: scale(0.45); }
          60% { opacity: 1; transform: scale(1.05); }
          100% { opacity: 1; transform: scale(1); }
        }
        @keyframes cpShimmer {
          0% { left: -60%; opacity: 0; }
          20% { opacity: 1; }
          100% { left: 120%; opacity: 0; }
        }
        @keyframes cpRiseUp {
          0% { opacity: 0; transform: translateY(28px); }
          100% { opacity: 1; transform: translateY(0); }
        }
        @keyframes cpFadeOut {
          0% { opacity: 1; }
          100% { opacity: 0; }
        }
      `}</style>
    </div>
  )
}

const estilos = {
  contenedor: {
    position: 'fixed', inset: 0,
    background: 'radial-gradient(circle at 50% 42%, #0F2A22 0%, #0a1410 55%, #06100C 100%)',
    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
    zIndex: 9999, overflow: 'hidden',
    animation: 'cpFadeOut 0.5s ease 2.7s forwards',
  },
  glow: {
    position: 'absolute', width: '430px', height: '430px', borderRadius: '50%',
    background: 'radial-gradient(circle, rgba(245,200,90,0.28) 0%, rgba(245,200,90,0.09) 42%, transparent 70%)',
    top: '40%', left: '50%', transform: 'translate(-50%, -50%) scale(0.6)',
    opacity: 0, animation: 'cpGlowIn 3.4s ease forwards',
  },
  ollaWrap: {
    position: 'relative', width: 'min(280px, 64vw)', aspectRatio: '1 / 1',
    display: 'flex', alignItems: 'center', justifyContent: 'center', marginTop: '-26px', zIndex: 2,
  },
  olla: {
    width: '100%', height: '100%', objectFit: 'contain',
    opacity: 0, transform: 'scale(0.45)',
    filter: 'drop-shadow(0 8px 26px rgba(245,200,90,0.22))',
    animation: 'cpOllaPop 1.0s cubic-bezier(0.34,1.56,0.64,1) 0.25s forwards',
  },
  shimmer: {
    position: 'absolute', top: '8%', left: '-60%', width: '52%', height: '84%',
    background: 'linear-gradient(105deg, transparent 0%, rgba(255,245,210,0) 38%, rgba(255,245,210,0.45) 50%, rgba(255,245,210,0) 62%, transparent 100%)',
    transform: 'skewX(-18deg)', opacity: 0, pointerEvents: 'none',
    animation: 'cpShimmer 0.95s ease 1.15s forwards',
  },
  wordmark: {
    margin: '14px 0 0', fontSize: '40px', fontWeight: 600, letterSpacing: '0.5px',
    opacity: 0, transform: 'translateY(28px)', zIndex: 2,
    animation: 'cpRiseUp 0.7s ease 1.55s forwards',
  },
  cocina: { color: '#D9DCE1' },
  pae: { color: '#F5C85A' },
  tagline: {
    margin: '11px 0 0', fontSize: '12px', letterSpacing: '1.8px', textTransform: 'uppercase',
    color: 'rgba(216,220,225,0.6)', opacity: 0, transform: 'translateY(14px)',
    textAlign: 'center', padding: '0 26px', zIndex: 2,
    animation: 'cpRiseUp 0.7s ease 2.0s forwards',
  },
}

export default IntroCocinaPAE
